import { useLocation } from "react-router-dom";
import "./styles/LibrarianBooks.css";

function LibrarianBooks() {
  const location = useLocation();
  const genre = location.state?.genre || "Literature";

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">
        Manage {genre} Books
      </h1>

      <div className="dashboard-center">
        
        <div className="dash-card">➕ Add New Book</div>
        <div className="dash-card">✏️ Update Book Status</div>
        <div className="dash-card">❌ Remove Book</div>
      </div>
    </div>
  );
}

export default LibrarianBooks;
